definition.script:
pipeline {
    agent any

    environment {
        DOCKER_COMPOSE_FILE = 'docker-compose.yml'
    }

    stages {
        stage('Checkout') {
            steps {
                git branch: 'main', url: 'https://github.com/Ashwinth-dk/Devops_Docker.git'
            }
        }

        stage('Build Backend') {
            steps {
                sh 'docker build -t organizeme-backend:test ./Server'
            }
        }

        stage('Build Frontend') {
            steps {
                sh 'docker build -t organizeme-frontend:test ./Frontend'
            }
        }

        stage('Test') {
            steps {
                sh 'docker compose -f $DOCKER_COMPOSE_FILE up -d postgres'
                sh 'sleep 30'
                sh 'docker compose -f $DOCKER_COMPOSE_FILE run --rm backend npm test || true'
            }
        }

        stage('Deploy') {
            steps {
                sh 'docker compose -f $DOCKER_COMPOSE_FILE up -d --build'
            }
        }
    }

    post {
        always {
            sh 'docker compose -f $DOCKER_COMPOSE_FILE down'
        }
    }
}
